// Ohmmeter! Identify an unknown resistor with one known resistor.
//
// Wire:  3V3 -> unknown R -> GPIO1   and   GPIO1 -> known 1k -> GND
// The pair divides 3.3 V; from the midpoint we solve for the unknown:
//     R = R_known * (3300 - mv) / mv
//
// IMPORTANT: the ESP32 ADC tops out near ~3.1 V (readings peg at 3100),
// so the reference works best within ~10x of the unknown. This script
// detects pegged readings and tells you which way to swap.
//
// In this example the "unknown" is a 4.7k so the sim can demo it.

const KNOWN = 1000.0;                // your reference resistor, ohms

fn on_start() {
    pin(1).watch_analog(200);        // ADC samples every 200 ms
    this.last = 0;
    log("measuring the resistor between 3V3 and GPIO1...");
}

fn on_tick(dt_ms) {
    let mv = pin(1).millivolts();
    if mv == 0 {
        return;                      // no sample yet
    }
    if mv >= 2950 {
        report(0, "pegged HIGH - unknown is much smaller than the reference; use a smaller known R");
        return;
    }
    if mv <= 100 {
        report(0, "pegged LOW - unknown is much bigger than the reference; use a bigger known R");
        return;
    }
    let r = (KNOWN * (3300.0 - mv.to_float()) / mv.to_float()).to_int();
    report(r, `= ${r} ohm, nearest standard: ${e12(r)} ohm  (GPIO1 at ${mv} mV)`);
}

// Log only when the value moved by more than ~5%.
fn report(r, text) {
    if (r - this.last).abs() * 20 > this.last || (r == 0 && this.last != 0) {
        this.last = r;
        log(text);
    }
}

// Snap to the closest E12 series value (what resistors actually come in).
fn e12(r) {
    if r <= 0 { return 0; }
    let series = [10, 12, 15, 18, 22, 27, 33, 39, 47, 56, 68, 82];
    let scale = 1;
    let base = r;
    while base >= 100 {
        base /= 10;
        scale *= 10;
    }
    let best = 10;
    let dist = 999999;
    for s in series {
        let d = (s - base).abs();
        if d < dist {
            dist = d;
            best = s;
        }
    }
    best * scale
}
